#include <iostream>
#include <unordered_map>
#include <string>

using namespace std;

int main()
{
    string word = "banana";
    unordered_map<char, int> freq;

    for (char c : word)
    {
        freq[c]++; // if c is new, freq[c] starts at 0 (the map gotcha working IN OUR FAVOR), then increments
    }

    cout << freq['a'] << endl;
    cout << freq['n'] << endl;
    cout << freq['b'] << endl;

    return 0;
}

